files.patch:
@@ -8,11 +8,18 @@
     1. user-supplied jwt.secret (explicit, reproducible)
     2. existing Secret's jwt-secret (upgrade path — keeps JWTs stable)
     3. fresh randAlphaNum 64 (first install only)
+
+  #6348: skip the `lookup` entirely when the user provides an explicit
+  jwt.secret. Helm identities with create/update but no `get` on Secrets
+  would otherwise fail at install time even though the lookup result is
+  never needed in that path.
 */}}
-{{- $existing := lookup "v1" "Secret" .Release.Namespace (include "kubestellar-console.fullname" .) }}
 {{- $existingJwt := "" }}
-{{- if and $existing $existing.data }}
-{{-   $existingJwt = index $existing.data "jwt-secret" | default "" }}
+{{- if not .Values.jwt.secret }}
+{{-   $existing := lookup "v1" "Secret" .Release.Namespace (include "kubestellar-console.fullname" .) }}
+{{-   if and $existing $existing.data }}
+{{-     $existingJwt = index $existing.data "jwt-secret" | default "" }}
+{{-   end }}
 {{- end }}
 apiVersion: v1
 kind: Secret
